VALUES
  ('islands-e3452428-moex-00110', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？ 沒入亦為行政罰之種類 違反行政法上義務之結果發生地在中華民國者，應受處罰 因避免他人名譽受損所為不得已之緊急避難行為，不受處罰 違反行政法上義務之行為，非出於故意者，均不予處罰', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00111', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政罰之裁處權時效，下列敘述何者正確？ 裁處權時效期間，自違反行政法上義務之行為終了時起算 行政罰之裁處因行政訴訟經撤銷而須另為裁處者，裁處權時效期間自行政法上義務之行為終了時 起算 行政罰之裁處權，因2年期間之經過而消滅 裁處權時效停止，自停止原因消滅之翌日起，裁處權時效期間重新起算', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00112', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政罰處罰法定原則之敘述，下列何者錯誤？ 處罰之依據不限於立法院制定之法律 行政機關依職權訂定之行政規則亦得作為處罰之依據 行為後處罰之依據有所變更時，採取從新從輕原則 縣自治條例亦得規定勒令停工', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00113', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政罰之處罰對象，下列敘述何者正確？ 人民違反行政法上義務，於罰鍰處分作成前死亡者，依法仍應科處 行政罰法對於共同違反行政法上義務行為者，類推適用刑法規定 未滿14歲之人非屬行政罰之處罰對象 行政機關非屬行政罰之處罰對象', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00114', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者非法務部行政執行署各分署得依職權核發禁止命令之法定事項？ 禁止搭乘特定之交通工具  禁止每月生活費用超過一定金額 禁止為特定之投資    禁止清償與他人間所生之金錢借貸債務 3601', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00115', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '消防人員依消防法規定，因搶救火災而為達搶救之目的時，損壞人民之車輛。此一損壞車輛之行為， 依行政執行法規定，其法律性質為何？ 即時強制、事實行為   即時強制、行政處分 直接強制、事實行為   直接強制、行政處分', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00116', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列行政行為，何者不適用行政程序法之程序規定？ 提供人民社會救助 否准外國人出入境 政府採購招標過程中，不予發還押標金之處分 違反食品衛生管理法規之處罰', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00117', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '依行政程序法規定，下列何者非行政程序之當事人？ 甲申請廢止他人註冊之商標 乙擔任申請補助案件之輔佐人 丙向主管機關表達開放高鐵上飲食之訴求 丁經主管機關通知後，參加鄰近危老建築重建計畫', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00118', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '甲、乙發生車禍，警察依法取得車禍附近道路監視器及第三人丙行車記錄器之錄影，下列敘述何者錯 誤？ 警察機關依其職權於公用道路設置監視器取得錄影，屬政府資訊 丙同意交付其行車記錄器錄影於警察後，該錄影仍屬丙個人資訊，非政府資訊 道路錄影與甲、乙權益無關之路人臉部特徵，屬於個人隱私，不得任意提供 警察提供肇事前後關鍵錄影時，應遮蔽無關路人之可識別資訊', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00119', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於提起訴願之期間，下列何者正確？ 自行政處分作成之日起15日內  自行政處分作成之次日起15日內 自行政處分達到之日起30日內  自行政處分達到之次日起30日內', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL)
